import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { studentActions } from '../../actions';
import { StudentSubjectScoreSheet } from './StudentSubjectScoreSheet';
import { Paper, Typography, Button } from '@material-ui/core';
import {SelectedInfo } from '../../../../includes';
import ReactToPrint from 'react-to-print';

const style = theme => ({
    root: {
    },
    termCard : {
        padding : 10
    },
    scoreSheet : {
        marginTop : 20
    },
    termHeaderContainer : {
        display :"flex",
        justifyContent : "center"
    },
    termHeader : {
        margin :"20px 0px",
        textAlign : "center"
    }
})
class _StudentAcad extends Component {
    constructor(props) {
        super(props);
        this.state = {
            studentAcadInfo : null,
            subjectAssessment : null
        }
        this.studentId = props.studentId;
        
    }
    printComponent = [];
    componentDidMount(){
        this.getStudentAcadData();
    }
    getStudentAcadData(){
        studentActions.getStudentAcademicInfo_NO_DISPATCH(
            this.studentId,
            1,
            (done, result, message)=>{
                if(done) this.setState({studentAcadInfo : result});
            }
        )
        studentActions.getSubjectsAndAssessments_NO_DISPATCH(
            1,1,
            (done, result, message)=>{
                if(done) this.setState({subjectAssessment: result});
            }
        )
    }
    render() {
        const {classes} = this.props;
        const {subjectAssessment = {}, studentAcadInfo = {}} = this.state;
        return (
            <div className={classes.root}>
                {studentAcadInfo && studentAcadInfo.terms && 
                studentAcadInfo.terms.map((termInfo, index)=>{
                    /**
                     * TO DO
                     * add all these information
                     */
                    let infoData = {
                        fullName : "Agu Chijioke C.",
                        paymentRef : termInfo.paymentRef,
                        Attendance : "79%",
                        position : 7
                    };
                    return <Fragment key={index}>
                        <Paper ref={e => this.printComponent[index] = e} className={classes.termCard}>
                            <div className={classes.termHeaderContainer}>
                                <Typography 
                                    className={classes.termHeader} 
                                    component="strong" variant="h4">
                                    {termInfo.termName}</Typography>
                            </div>
                            <SelectedInfo
                                selectedInfo={infoData}
                                skip={[]}
                                nameMapping={name=>name}
                                valueMapping={(name, value)=>value}
                                outlined
                                />
                             <div style={{marginTop: 20}}>{termInfo.remark && <div>
                                <Typography component="strong" variant="h6">Remark ({termInfo.remark.short})</Typography>
                                <Typography>{termInfo.remark.description}</Typography>
                                </div>}
                            </div>
                            <StudentSubjectScoreSheet
                                classes={{root : classes.scoreSheet}}
                                {...subjectAssessment}
                                studentAssessments={termInfo.subjects || []}
                                termName={termInfo.termName}
                            />
                           
                        </Paper>
                        <ReactToPrint
                            trigger={() => <Button variant="text">{"Print "+String(termInfo.termName).toLowerCase()+" score sheet!"}</Button>}
                            content={() => this.printComponent[index]}
                        />
                    </Fragment>
                })}
            </div>
        );
    }
}


_StudentAcad.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = state => ({
    state
})


export const StudentAcad = connect(mapStateToProps)(withStyles(style)(_StudentAcad));