import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, breadCrumbActions, mainStageHeaderAction, MyCustomTabs, headerStrings } from '../../../includes';
import { StudentInfo } from './StudentInfo/StudentInfo';
import { StudentAcad } from './StudentAcad/StudentAcad';
import { StudentGroups } from './StudentGroups/StudentGroups';
import { routeNamesSchool } from '../../routeNames';


const style = theme => ({
    root: {
    },
    viewContainer : {
        marginTop : 20
    }
})
class _StudentProfile extends Component {
    constructor(props) {
        super(props);
        this.state = {
            tabValue : null
        }
        const {dispatch} = this.props;
        headerActions({
            [headerStrings.headerTitle] : "STUDENT PROFILE",
            [headerStrings.backButtonAction] : ()=>{}
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesSchool.dashboard},
            {name : "Students", path : routeNamesSchool.students},
            {name : "Profile", path : routeNamesSchool.studentProfile},
        ])(dispatch);
        mainStageHeaderAction({})(dispatch);
    }
    
    getTabContext = context => this.tabContext = context;
    render() {
        const {classes} = this.props;
        const {tabValue} = this.state;
        return (
            <div className={classes.root}>
                <MyCustomTabs
                    position="sticky"
                    tabs={{
                        info : "Info", 
                        acad : "Academics", 
                        group: "Category",
                    }}
                    getContext={this.getTabContext}
                    getInitialTabValue={tabValue=>this.setState({tabValue})}
                    />
                <div className={classes.viewContainer}>
                    {tabValue === "info" && <StudentInfo studentId={1}/>}
                    {tabValue === "acad" && <StudentAcad studentId={1}/>}
                    {tabValue === "group" && <StudentGroups studentId={1}/>}
                </div>
            </div>
        );
    }
}


_StudentProfile.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = state => ({
    state
})


export const StudentProfile = connect(mapStateToProps)(withStyles(style)(_StudentProfile));
export {StudentProfile as default};