import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { MyTable } from '../../../../includes';
import ReactToPrint from "react-to-print";
import { Typography, Paper } from '@material-ui/core';
import { scorePositionLiteral } from '../../../../../utils';
const style = theme => ({
    root: {
        
    }
})
class _StudentSubjectScoreSheet extends Component {
    getHeader(assessments){
        let header = ["Subjects"];
        let dataMap = ["subject"];
        for (let i = 0; i < assessments.length; i++) {
            const assessment = assessments[i];
            header.push(assessment.name);
            dataMap.push(assessment._id);
        }
        header.push("Total", "Grade", "Class Pos.", "Level Pos.");
        dataMap.push("total", "grade", "classPosition", "levelPosition");
        return {header, dataMap};
    }
    /**
     * TO DO
     * get this form the database
     * and do the setup in the settings 
     */
    gradingData = [
        {_id : 1, literal : "A", operator : "gte", points : [70]},
        {_id : 2, literal : "B", operator : "btw", points : [60, 69]},
        {_id : 3, literal : "C", operator : "btw", points : [50, 59]},
        {_id : 4, literal : "D", operator : "btw", points : [45, 49]},
        {_id : 5, literal : "E", operator : "btw", points : [30, 45]},
        {_id : 6, literal : "F", operator : "lte", points : [29]},
    ]
    literalGrade(lit, grade){
        for (let i = 0; i < lit.length; i++) {
            const {operator, points, literal} = lit[i];
            switch(operator){
                case "gte" : 
                    if(points[0] <= grade) 
                        return literal;
                    break;
                case "btw" : 
                    if(points[0] >= grade <= points[1])
                        return literal;
                case "lte" :
                    if(points[0] >= grade)
                        return literal;
                    break;
            }
        }
    }
    getData(subjects, studentSubjects){
        let data = [];
        for (let i = 0; i < subjects.length; i++) {
            const subject = subjects[i];
            const {subjectName, _id : subjectId} = subject;
            let dataItem = {subject : subjectName};
            for (let k = 0; k < studentSubjects.length; k++) {
                const studentSubj = studentSubjects[k];
                if(subjectId === studentSubj.sessionSubjectId){
                    const {assessments, classPosition, levelPosition} = studentSubj;
                    let total = 0;
                    for (let n = 0; n < assessments.length; n++) {
                        const studAss = assessments[n];
                        dataItem[studAss._id] = studAss.score
                        total += studAss.score;
                    }
                    dataItem.total = total;
                    dataItem.grade = this.literalGrade(this.gradingData, total);
                    dataItem.classPosition = scorePositionLiteral(classPosition);
                    dataItem.levelPosition = scorePositionLiteral(levelPosition);
                }
            }
            data.push(dataItem);
        }
        return data;
    }
    getDataMap(){

    }
    render() {
        const {
            subjects, assessmentNames, studentAssessments
        } = this.props;
        const {classes} = this.props;
        const {header, dataMap} = this.getHeader(assessmentNames);
        return (
            <div className={classes.root}>
                <MyTable
                    elevation={0}
                    ref={el => this.printComponent = el}
                    title={"Score Sheet"}
                    header={header}
                    dataMap={dataMap}
                    data={this.getData(subjects, studentAssessments)}
                    />
            </div>
        );
    }
}
_StudentSubjectScoreSheet.propTypes = {
    classes : PropTypes.object.isRequired,
    subjects : PropTypes.array,
    assessmentNames : PropTypes.array,
    studentAssessments : PropTypes.array,
    remark : PropTypes.object,
};
export const StudentSubjectScoreSheet = withStyles(style)(_StudentSubjectScoreSheet);