import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Grid } from '@material-ui/core';
import { SimpleListBoard } from '../../../../includes';
import { studentStrings, nameMapper } from '../../config';
import { studentActions } from '../../actions';


const style = theme => ({
    root: {
    },
    imgContainer :{
        display : "flex",
        justifyContent : 'center',
        alignItems : "center"
    },
    img : {
        borderRadius : "100%",
        width : 200,
        height : 200
    }
})
class _StudentInfo extends Component {
    constructor(props) {
        super(props);
        this.studentId = props.studentId || 1;
        this.getStudentInfo();
    }
    getStudentInfo(){
        const {
            [studentStrings.studentProfile] : studentProfile,
            dispatch
        } = this.props;
        if(!studentProfile) studentActions.getStudentInfo(this.studentId)(dispatch);
    }
    
    academinInfoShow = [
        "currentSessionLevel", "currentSessionClass", 
        "lastLevelPosition", "lastClassPosition"
    ];
    render() {
        const {
            classes,
            [studentStrings.studentProfile] :studentProfile
        } = this.props;
        const acadInfo = studentProfile ? studentProfile.acadInfo:{};
        const bioInfo = studentProfile ? studentProfile.bioInfo:{};
        const contactInfo = studentProfile ? studentProfile.contactInfo:{};
        const parentInfo = studentProfile ? studentProfile.parentInfo: {};
        return (
            <Grid container spacing={2} className={classes.root}>
                <Grid item xs={12} sm={12} md={6} lg={6} xl={6}>
                    <div className={classes.imgContainer}>
                        <img src="/images/sch_children.jpeg" title="passport" className={classes.img}/>
                    </div>
                </Grid>
                <Grid item xs={12} sm={12} md={6} lg={6} xl={6}>
                    <SimpleListBoard
                        title="Academic Info"
                        data={acadInfo}
                        nameMapper={nameMapper}
                        show={this.academinInfoShow}
                        valueMapper={(name, value)=>value}
                        />
                </Grid>
                <Grid item xs={12} sm={12} md={6} lg={6} xl={6}>
                    <SimpleListBoard
                        title="Bio Info"
                        data={bioInfo}
                        nameMapper={nameMapper}
                        skip={[]}
                        valueMapper={(name, value)=>value}
                        />
                </Grid>
                <Grid item xs={12} sm={12} md={6} lg={6} xl={6}>
                    <SimpleListBoard
                        title="Contact Info"
                        data={contactInfo}
                        nameMapper={nameMapper}
                        skip={[]}
                        valueMapper={(name, value)=>value}
                        />
                </Grid>
                <Grid item xs={12} sm={12} md={6} lg={6} xl={6}>
                    <SimpleListBoard
                        title="Parent's Info"
                        data={parentInfo}
                        nameMapper={nameMapper}
                        skip={[]}
                        valueMapper={(name, value)=>value}
                        />
                </Grid>
                <Grid item xs={12} sm={12} md={6} lg={6} xl={6}>
                    <SimpleListBoard
                        title="Statistic"
                        data={{}}
                        nameMapper={nameMapper}
                        skip={[]}
                        valueMapper={(name, value)=>value}
                        />
                </Grid>
            </Grid>
        );
    }
}


_StudentInfo.propTypes = {
    classes : PropTypes.object.isRequired,
    studentId : PropTypes.number,
};
const mapStateToProps = ({studentReducer}) => ({
    [studentStrings.studentProfile] : studentReducer[studentStrings.studentProfile]
})


export const StudentInfo = connect(mapStateToProps)(withStyles(style)(_StudentInfo));