import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { studentStrings, nameMapper } from '../../config';
import { studentActions } from '../../actions';
import { FormDisplay, SimpleListBoard } from '../../../../includes';
import { Button } from '@material-ui/core';


const style = theme => ({
    root: {
    }
})
class _StudentGroups extends Component {
    constructor(props) {
        super(props);
        this.state = {
            editMode : false
        }
        this.studentId = props.studentId;
        this.initializeComponent();
    }
    initializeComponent(){
        const {
            [studentStrings.studentGroupForm] : studentGroupForm,
            [studentStrings.studentProfile] : studentProfile,
            dispatch
        } = this.props;
        if(!studentProfile) 
            studentActions.getStudentInfo(this.studentId)(dispatch);
        if(!studentGroupForm)
            studentActions.getStudentGroupForm()(dispatch);
    }
    getStudentGroupData(profile){
        const {acadInfo} = profile || {};
        let data = {};
        if(acadInfo) for (const key in acadInfo) {
            if (acadInfo.hasOwnProperty(key)) {
                const value = acadInfo[key];
                switch(key){
                    case "currentSessionLevelId":
                        data["level"] = value; break;
                    case "currentSessionClassId" :
                        data["class"] = value; break;
                }
            }
        }
        data.house = 1;
        return data;
    }
    updateGroups(){
        
        this.setState({editMode: false})
    }
    render() {
        const {
            classes,
            [studentStrings.studentGroupForm] : studentGroupForm,
            [studentStrings.studentProfile] : studentProfile,
        } = this.props;
        console.log(this.state);
        return (
            <div className={classes.root}>
                <FormDisplay
                    {...studentGroupForm}
                    formData={this.getStudentGroupData(studentProfile)}
                    fieldProps={{disabled : !this.state.editMode}}
                    footer={
                        <div>
                            {this.state.editMode ?
                            <Button variant="contained" color="primary" onClick={()=>this.updateGroups()}>
                                Update
                            </Button>:
                            <Button variant="contained" color="primary" onClick={()=>this.setState({editMode: true})}>
                                Edit
                            </Button>}
                        </div>
                    }
                    />
            </div>
        );
    }
}


_StudentGroups.propTypes = {
    classes : PropTypes.object.isRequired,
    studentId : PropTypes.number.isRequired,
};

const mapStateToProps = ({studentReducer}) => ({
    [studentStrings.studentProfile] : studentReducer[studentStrings.studentProfile],
    [studentStrings.studentGroupForm] : studentReducer[studentStrings.studentGroupForm]
})


export const StudentGroups = connect(mapStateToProps)(withStyles(style)(_StudentGroups));